def create_shelter_permissions(apps, schema_editor):
    """Create shelter-specific permissions on the Organization content type."""
    Organization = apps.get_model("organizations", "Organization")
    Permission = apps.get_model("auth", "Permission")
    ContentType = apps.get_model("contenttypes", "ContentType")
    ct = ContentType.objects.get_for_model(Organization)
    db_alias = schema_editor.connection.alias

    for codename, name in [
        ("manage_shelter", "Can manage shelters"),
        ("manage_shelter_beds", "Can manage shelter beds and rooms"),
    ]:
        Permission.objects.using(db_alias).get_or_create(
            codename=codename,
            content_type=ct,
            defaults={"name": name, "content_type": ct},
        )


